export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:30。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他還坐在書桌前。那張寫著「今天，我要看見 22:23」的紙被推到一旁。照片站位圖和最後清醒時間表並排攤著。雨聲比半小時前小了一點，但天色沒有亮多少。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有起身。他從抽屜裡再抽出一張空白活頁紙，攤在另外兩張下面。三張紙排成一列——照片、紀錄、接下來要做的事。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今天不查案。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今天只做一件事——活著看見 22:23。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)要做到這件事，我得先把前四次死在哪、為什麼死，全部變成「今天不要去哪裡」。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他提起筆。先在紙的正中央畫了一個長方形——校園外框。和上一輪那張地圖一樣的輪廓。但這一次他不標權限。他要標的是——哪裡會殺人，哪裡只能看，哪裡相對安全。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在地圖上方那座細長的塔狀符號上，重重塗了一層陰影。然後在旁邊寫了兩個字。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "**危險。**", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一輪。22:22。停電。監控空白。黑雨衣。從那裡墜落。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)校務車裝卸區深處。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "右側邊緣的虛線車道上，他畫了一個叉。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二輪。後山維修路。攔截。失控。車廂翻覆。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)醫務室。南翼走廊。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下方那個帶十字的方塊，他同樣塗黑。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三輪。門從外面鎖上。藥少了。監控空白。被隔離。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)校史館後方。地下維修通道。舊機房。泵房。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "中間偏左，他畫了一條向下的細線，通往一個小小的方塊。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第四輪。地下。倒灌。水。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)還有指揮室。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把那個代表指揮室的圓圈也塗掉了。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第三輪。我把線索交進去，人就被送進死角。指揮室不是安全的地方。它是把不安全派發出去的地方。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "五個黑點。四條命。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在這五個位置外面畫了一個圈——沒有紅筆，他用筆尖把圈描了三遍，讓線條發黑發亮。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "圈旁邊寫了三個字。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "**危險區。**", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今天——這五個地方，一個都不進。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他在圈外側，又畫了一圈。這一圈用虛線。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館外走廊。禮堂後台入口。基座暫存動線。直播控制台外側通道。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這些地方——可以經過，可以遠遠看。但腳不能停下來，手不能伸進去。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "虛線圈旁邊，他寫了六個字。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "**可觀察，不進入。**", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)上一輪我就是停在這條線上太久，才被拉進地下的。今天走到這條線，看一眼，就走。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最後，他在地圖最外圍——所有建築的開放邊緣——畫了第三圈。這一圈用輕輕的、連續的實線。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "禮堂觀眾席。禮堂大門附近。家長休息區。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在這一圈裡寫了一行小字。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有攝影機。有志工。有媒體。有老師。有家長。有人看得到的地方。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "圈旁寫了四個字。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "**相對安全。**", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今天，我只待在這裡面。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三圈畫完。地圖像一張靶紙——最裡面是墳場，中間是警戒線，最外面才是他今天能站的地方。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把筆放下。看了三秒。然後提起筆，翻到紙的背面。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)光知道不去哪裡還不夠。得有規則。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在背面頂端寫了「規則」兩個字。然後一條一條往下寫。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一條：不單獨行動超過五分鐘。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)前四次每一次出事，身邊都沒有別人。今天只要離開人群超過五分鐘，就立刻回來。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二條：不進任何需要門禁卡的地方。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓、醫務室、指揮室、地下——全都需要門禁。只要有門禁的地方，就有人能從外面鎖。今天只走不需要刷卡就能進出的路。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三條：不把訊息交給任何大人。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第三輪。我把手機交給邵叔。然後我被鎖進醫務室。訊息、手機、筆記——今天一樣都不交出去。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第四條：21:45 監控切線期間，只待在有人看得到的地方。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十七分鐘。上一輪就是在這段空白裡進的地下。今天 21:45 一到，我就站進禮堂觀眾席最擠的那一排。誰也帶不走我。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第五條：22:20 到 22:30，絕不離開禮堂公開區。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這是十分鐘。從 22:20 到 22:30。我站在禮堂大門口。身邊是家長、是直播鏡頭、是志工。我什麼都不做。我就看手機。看時間從 22:22 跳到 22:23。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)看一眼——22:23 那邊，到底有什麼。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "五條規則寫完。他放下筆。手指按在第五條的末尾，停了很久。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯這五條，全是為了保住我自己。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外有鳥叫了一聲，又被雨蓋過去。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把地圖翻回正面。視線落在照片站位圖上——父親、姓許的女人、邵叔、年幼的自己。他在「許」字旁邊，用很小的字跡補了一個名字。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她總在出事的地點附近。她有相機。訊息可能和她有關。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但今天——", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他頓了一下。筆尖懸在「許星棠」三個字上面。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今天我的任務是看見 22:23。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是她。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)她今天做什麼，不關我的事。我只要保住自己。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把「許星棠」三個字圈了一下。沒有再多寫。然後把三張紙疊在一起，折好，塞進校服胸前口袋。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿起手機。螢幕還朝下扣著。他沒有翻開。但那條訊息的第三句還壓在他腦子裡——像一根刺，從早上七點十二分紮進來，到現在還沒拔掉。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「不要把相機交給任何大人。」", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯相機。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)相機到底在誰手裡？", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他皺起眉。這個問題他問過自己四輪了。每一輪都沒有答案。黑雨衣在找相機。校務車上放著空包。訊息叫他不要把相機交出去。可他從來沒有拿過那台相機。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果這條訊息——不是在警告我。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而是在保護別的什麼東西——", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不對。別想了。今天不查這個。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手機塞進口袋。站起來。08:24。廣播響了——和每一輪一樣的開場白，叫志工到一樓大廳集合。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)今天，做一個正常的高三學生。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)去簽到。去搬水。去聽班導講話。去吃飯。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不查案。不跟人。不進危險區。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)然後活著——看見 22:23。", background: Background.Chapter_5_Ch5_Act1_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拉開宿舍門。走廊上已經有腳步聲。雨聲。人聲。世界像一台機器，喀噠一聲，開始運轉今天的劇本。", background: Background.Chapter_5_Ch5_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走進去。和所有人一樣。", background: Background.Chapter_5_Ch5_Act1_S0 },
];
